import{_ as e,o as t,c as r,ah as i}from"./chunks/framework.Bg572dcY.js";const m=JSON.parse('{"title":"TCP 调优","description":"","frontmatter":{"title":"TCP 调优","order":4},"headers":[],"relativePath":"server/network/tcp-tuning.md","filePath":"server/network/tcp-tuning.md"}'),n={name:"server/network/tcp-tuning.md"};function s(l,a,o,p,c,h){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="linux-tcp-参数调优" tabindex="-1">linux TCP 参数调优 <a class="header-anchor" href="#linux-tcp-参数调优" aria-label="Permalink to “linux TCP 参数调优”">​</a></h1><p>Linux 提供了大量可调优的 TCP 参数，正确配置可以显著提升服务端性能。本节从连接建立、数据传输、连接释放三个阶段介绍关键参数。</p><h2 id="连接建立阶段" tabindex="-1">连接建立阶段 <a class="header-anchor" href="#连接建立阶段" aria-label="Permalink to “连接建立阶段”">​</a></h2><h3 id="somaxconn" tabindex="-1">somaxconn <a class="header-anchor" href="#somaxconn" aria-label="Permalink to “somaxconn”">​</a></h3><p>syns 队列的最大长度，默认 128。高并发场景下，128 太小，导致连接被丢弃。建议设置为 4096 或更高。sysctl -w net.core.somaxconn=4096。</p><h3 id="synack-retries" tabindex="-1">synack_retries <a class="header-anchor" href="#synack-retries" aria-label="Permalink to “synack_retries”">​</a></h3><p>发送 SYN+ACK 的重试次数，默认 5 次（约 30 秒）。重试次数太多，半连接队列占用时间长。建议设置为 2-3 次。sysctl -w net.ipv4.tcp_synack_retries=2。</p><h3 id="syncookies" tabindex="-1">syncookies <a class="header-anchor" href="#syncookies" aria-label="Permalink to “syncookies”">​</a></h3><p>开启 syncookies 可以防止 SYN 泛洪攻击，但会禁用一些 TCP 选项（如窗口扩大）。默认关闭，攻击时开启。sysctl -w net.ipv4.tcp_syncookies=1。</p><h3 id="tw-reuse" tabindex="-1">tw_reuse <a class="header-anchor" href="#tw-reuse" aria-label="Permalink to “tw_reuse”">​</a></h3><p>允许 TIME_WAIT 状态的 socket 用于新连接。默认关闭，建议开启。高并发短连接场景下，TIME_WAIT 状态的 socket 太多，占用端口。sysctl -w net.ipv4.tcp_tw_reuse=1。</p><h3 id="abort-on-overflow" tabindex="-1">abort_on_overflow <a class="header-anchor" href="#abort-on-overflow" aria-label="Permalink to “abort_on_overflow”">​</a></h3><p>syns 队列满时，是否直接发送 RST。默认关闭，建议保持关闭。开启会导致客户端连接失败，而不是排队等待。</p><h2 id="数据传输阶段" tabindex="-1">数据传输阶段 <a class="header-anchor" href="#数据传输阶段" aria-label="Permalink to “数据传输阶段”">​</a></h2><h3 id="rmem-max-wmem-max" tabindex="-1">rmem_max/wmem_max <a class="header-anchor" href="#rmem-max-wmem-max" aria-label="Permalink to “rmem_max/wmem_max”">​</a></h3><p>接收/发送缓冲区的最大值，默认约 128KB。高带宽延迟积（BDP）的网络需要更大的缓冲区。计算公式：带宽 × 延迟。例如 1Gbps、100ms 延迟，BDP = 1Gbps × 0.1s = 12.5MB。建议设置为 BDP 的两倍。</p><h3 id="rmem-default-wmem-default" tabindex="-1">rmem_default/wmem_default <a class="header-anchor" href="#rmem-default-wmem-default" aria-label="Permalink to “rmem_default/wmem_default”">​</a></h3><p>接收/发送缓冲区的默认值，默认约 128KB。建议根据应用调整，Web 服务建议 256KB，大文件传输建议更大。</p><h3 id="tcp-fastopen" tabindex="-1">tcp_fastopen <a class="header-anchor" href="#tcp-fastopen" aria-label="Permalink to “tcp_fastopen”">​</a></h3><p>开启 TCP Fast Open（TFO），允许在三次握手期间传输数据。默认关闭，建议开启。TFO 减少 1 个 RTT，但需要客户端支持。</p><h3 id="tcp-notsent-lowat" tabindex="-1">tcp_notsent_lowat <a class="header-anchor" href="#tcp-notsent-lowat" aria-label="Permalink to “tcp_notsent_lowat”">​</a></h3><p>发送缓冲区未发送数据的最低阈值，低于此阈值时不再发送。默认 -1（禁用），建议设置为 16KB。可以减少小包发送，提高吞吐量。</p><h2 id="连接释放阶段" tabindex="-1">连接释放阶段 <a class="header-anchor" href="#连接释放阶段" aria-label="Permalink to “连接释放阶段”">​</a></h2><h3 id="fin-timeout" tabindex="-1">fin_timeout <a class="header-anchor" href="#fin-timeout" aria-label="Permalink to “fin_timeout”">​</a></h3><p>FIN_WAIT_2 状态的超时时间，默认 60 秒。太长会占用资源，太短可能导致连接关闭不完整。建议设置为 30 秒。</p><h3 id="keepalive-time" tabindex="-1">keepalive_time <a class="header-anchor" href="#keepalive-time" aria-label="Permalink to “keepalive_time”">​</a></h3><p>TCP keepalive 的空闲时间，默认 7200 秒（2 小时）。太长会导致僵尸连接占用资源，太短会增加网络流量。建议设置为 600 秒。</p><h3 id="keepalive-probes" tabindex="-1">keepalive_probes <a class="header-anchor" href="#keepalive-probes" aria-label="Permalink to “keepalive_probes”">​</a></h3><p>TCP keepalive 的探测次数，默认 9 次。探测失败后关闭连接。建议设置为 3-5 次。</p><h3 id="keepalive-intvl" tabindex="-1">keepalive_intvl <a class="header-anchor" href="#keepalive-intvl" aria-label="Permalink to “keepalive_intvl”">​</a></h3><p>TCP keepalive 的探测间隔，默认 75 秒。建议设置为 15-30 秒。</p><h2 id="性能参数" tabindex="-1">性能参数 <a class="header-anchor" href="#性能参数" aria-label="Permalink to “性能参数”">​</a></h2><h3 id="tcp-slow-start-after-idle" tabindex="-1">tcp_slow_start_after_idle <a class="header-anchor" href="#tcp-slow-start-after-idle" aria-label="Permalink to “tcp_slow_start_after_idle”">​</a></h3><p>空闲一段时间后，慢启动重新开始。默认开启，建议关闭。关闭后可以避免拥塞窗口不必要的缩小。</p><h3 id="tcp-no-metrics-save" tabindex="-1">tcp_no_metrics_save <a class="header-anchor" href="#tcp-no-metrics-save" aria-label="Permalink to “tcp_no_metrics_save”">​</a></h3><p>不保存连接的性能指标（如 RTT、拥塞窗口）。默认关闭，建议开启。开启后可以避免不同连接间的性能指标干扰。</p><h3 id="tcp-mtu-probing" tabindex="-1">tcp_mtu_probing <a class="header-anchor" href="#tcp-mtu-probing" aria-label="Permalink to “tcp_mtu_probing”">​</a></h3><p>开启 MTU 探测，避免 IP 分片。默认关闭，建议开启。开启后可以自动发现 MTU，减少分片开销。</p><h2 id="监控与调试" tabindex="-1">监控与调试 <a class="header-anchor" href="#监控与调试" aria-label="Permalink to “监控与调试”">​</a></h2><h3 id="ss-命令" tabindex="-1">ss 命令 <a class="header-anchor" href="#ss-命令" aria-label="Permalink to “ss 命令”">​</a></h3><p>ss -s：统计摘要。ss -t -a：显示所有 TCP 连接。ss -t -i：显示 TCP 详细信息（RTT、拥塞窗口）。</p><h3 id="tcpdump" tabindex="-1">tcpdump <a class="header-anchor" href="#tcpdump" aria-label="Permalink to “tcpdump”">​</a></h3><p>tcpdump -i eth0 -w capture.pcap：抓包保存到文件。tcpdump -r capture.pcap -A：以 ASCII 显示包内容。</p><h3 id="proc-net-tcp" tabindex="-1">/proc/net/tcp <a class="header-anchor" href="#proc-net-tcp" aria-label="Permalink to “/proc/net/tcp”">​</a></h3><p>/proc/net/tcp 文件包含所有 TCP 连接的状态，可以用于监控和调试。</p><p>TCP 参数调优需要根据实际场景调整，没有万能配置。理解每个参数的含义和影响，才能做出正确的调优决策。</p>',46)])])}const _=e(n,[["render",s]]);export{m as __pageData,_ as default};
